import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.Vng7Hdlh.js";const m=JSON.parse('{"title":"List of interesting ParaSpell✨ repositories","description":"","frontmatter":{},"headers":[],"relativePath":"links.md","filePath":"links.md"}'),o={name:"links.md"};function s(l,e,n,p,c,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="list-of-interesting-paraspell✨-repositories" tabindex="-1">List of interesting ParaSpell✨ repositories <a class="header-anchor" href="#list-of-interesting-paraspell✨-repositories" aria-label="Permalink to &quot;List of interesting ParaSpell✨ repositories&quot;">​</a></h1><h2 id="packages-and-applications-🧰" tabindex="-1">Packages and applications 🧰 <a class="header-anchor" href="#packages-and-applications-🧰" aria-label="Permalink to &quot;Packages and applications 🧰&quot;">​</a></h2><h3 id="xcm-sdk-🪄" tabindex="-1">XCM-SDK 🪄 <a class="header-anchor" href="#xcm-sdk-🪄" aria-label="Permalink to &quot;XCM-SDK 🪄&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-tools/tree/main/packages/sdk" target="_blank" rel="noreferrer">SDK link</a> |<br> The SDK unifies various pallets, including <code>XCM</code>, <code>Transact</code>, <code>Swap</code> and <code>Asset pallet</code>, in a cohesive manner. It supports all XCM-compatible Parachains within the Kusama and the Polkadot ecosystems and is designed for ease of implementation, abstracting much of the complex logic and requiring only a few simple, user-friendly inputs.</p><h3 id="xcm-api-⚡️" tabindex="-1">XCM-API ⚡️ <a class="header-anchor" href="#xcm-api-⚡️" aria-label="Permalink to &quot;XCM-API ⚡️&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-tools/tree/main/apps/xcm-api" target="_blank" rel="noreferrer">API link</a> |<br> The XCM API serves as an enhancement for <code>XCM</code> and <code>Asset pallet</code>, designed to simplify the development process. By integrating the <code>XCM SDK</code> and its swap capabilities also, it enables dApp developers to incorporate XCM interoperability without the need to install additional packages, thereby saving both time and costs by offloading heavy computing tasks (such as call generation) from the application.</p><h3 id="xcm-analyser-🔎" tabindex="-1">XCM-Analyser 🔎 <a class="header-anchor" href="#xcm-analyser-🔎" aria-label="Permalink to &quot;XCM-Analyser 🔎&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-tools/tree/main/packages/xcm-analyser" target="_blank" rel="noreferrer">Analyser link</a> |<br> A tool designed to convert XCM locations into a human-readable format.</p><h3 id="xcm-visualizer-🖼️" tabindex="-1">XCM-Visualizer 🖼️ <a class="header-anchor" href="#xcm-visualizer-🖼️" aria-label="Permalink to &quot;XCM-Visualizer 🖼️&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-tools/tree/main/apps/visualizer-fe" target="_blank" rel="noreferrer">Visualizer link</a> |<br> A visualization tool for exploring XCM within the Polkadot ecosystem. It allows users to browse history, explore selected Parachains, filter accounts most engaged in XCM, and more, all within an exciting 3D universe-like visualization.</p><h3 id="xcm-playground-🛝" tabindex="-1">XCM-Playground 🛝 <a class="header-anchor" href="#xcm-playground-🛝" aria-label="Permalink to &quot;XCM-Playground 🛝&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-tools/tree/main/apps/playground" target="_blank" rel="noreferrer">Playground link</a> |<br> A sandbox environment that allows users to test all ParaSpell applications and packages, including the XCM SDK, XCM API, XCM Router, and XCM Analyser.</p><h3 id="paraspell-xcm-tools-landing-page-🛬" tabindex="-1">ParaSpell XCM Tools Landing page 🛬 <a class="header-anchor" href="#paraspell-xcm-tools-landing-page-🛬" aria-label="Permalink to &quot;ParaSpell XCM Tools Landing page 🛬&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-tools/tree/main/apps/site" target="_blank" rel="noreferrer">ParaSpell page link</a> |</p><p>A professional landing page for the XCM Tools, providing a clear overview of the capabilities that can be achieved through the XCM Tools.</p><h2 id="other-repositories-🛠️" tabindex="-1">Other repositories 🛠️ <a class="header-anchor" href="#other-repositories-🛠️" aria-label="Permalink to &quot;Other repositories 🛠️&quot;">​</a></h2><h3 id="presskit-🤵‍♂️" tabindex="-1">Presskit 🤵‍♂️ <a class="header-anchor" href="#presskit-🤵‍♂️" aria-label="Permalink to &quot;Presskit 🤵‍♂️&quot;">​</a></h3><p><a href="https://github.com/paraspell/presskit" target="_blank" rel="noreferrer">Presskit link</a> |</p><p>The Presskit contains ParaSpell logos for media and press use.</p><h3 id="docs-📖" tabindex="-1">Docs 📖 <a class="header-anchor" href="#docs-📖" aria-label="Permalink to &quot;Docs 📖&quot;">​</a></h3><p><a href="https://github.com/paraspell/docs" target="_blank" rel="noreferrer">Docs link</a> |<br> The documentation provides guidance on how to use the XCM Tool stack. It also includes useful links and important information about ParaSpell.</p><h3 id="xcm-sdk-starter-template-🛫" tabindex="-1">XCM SDK Starter template 🛫 <a class="header-anchor" href="#xcm-sdk-starter-template-🛫" aria-label="Permalink to &quot;XCM SDK Starter template 🛫&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-sdk-template" target="_blank" rel="noreferrer">XCM SDK Starter template link</a> |<br> The XCM SDK Starter template offers a ready-to-use base for developers to quickly integrate XCM functionality into their projects. With pre-configured settings and example use cases, this template reduces the complexity of setup and allows users to focus on building their applications with minimal friction.</p><h3 id="xcm-api-starter-template-🛫" tabindex="-1">XCM API Starter template 🛫 <a class="header-anchor" href="#xcm-api-starter-template-🛫" aria-label="Permalink to &quot;XCM API Starter template 🛫&quot;">​</a></h3><p><a href="https://github.com/paraspell/xcm-api-template" target="_blank" rel="noreferrer">XCM API Starter template link</a> |<br> The XCM API Starter template provides a streamlined foundation for utilizing the XCM API. It enables developers to quickly access XCM interoperability features and includes basic setups and instructions, making it easier to incorporate cross-chain interactions into dApps without needing to handle the heavy technical lifting.</p>',25)])])}const u=a(o,[["render",s]]);export{m as __pageData,u as default};
